# -----------------------------------------------------------------------------
# General helpers
# -----------------------------------------------------------------------------
def resolve_existing_path(candidates: list[Path]) -> Path | None:
    """Return the first existing file path from a list of candidates."""
    for path in candidates:
        if path.exists():
            return path
    return None


def image_to_data_uri(path: Path | None) -> str | None:
    """Convert a local image file to a data URI for use in HTML."""
    if path is None or not path.exists():
        return None

    suffix = path.suffix.lower()
    mime = {
        ".svg": "image/svg+xml",
        ".png": "image/png",
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".webp": "image/webp",
    }.get(suffix, "application/octet-stream")

    encoded = base64.b64encode(path.read_bytes()).decode("utf-8")
    return f"data:{mime};base64,{encoded}"


def svg_to_inline_html(path: Path, css_class: str, aria_label: str) -> str:
    """Inline an SVG file in HTML so Streamlit does not need to resolve image paths."""
    svg_text = path.read_text(encoding="utf-8", errors="ignore")
    svg_text = re.sub(r"<\?xml[^>]*\?>", "", svg_text)
    svg_text = re.sub(r"<!--.*?-->", "", svg_text, flags=re.DOTALL)
    svg_text = re.sub(
        r"<svg\b",
        f'<svg class="{css_class}" role="img" aria-label="{aria_label}"',
        svg_text,
        count=1,
    )
    return svg_text


def logo_to_html(
    candidates: list[Path],
    css_class: str,
    alt_text: str,
    fallback_text: str,
) -> str:
    """Render a local logo robustly, preferring inline SVG over file paths."""
    path = resolve_existing_path(candidates)

    if path is None:
        return f'<div class="header-fallback-logo">{fallback_text}</div>'

    if path.suffix.lower() == ".svg":
        return svg_to_inline_html(path, css_class=css_class, aria_label=alt_text)

    src = image_to_data_uri(path)
    if src:
        return f'<img class="{css_class}" src="{src}" alt="{alt_text}">'

    return f'<div class="header-fallback-logo">{fallback_text}</div>'


def clear_last_results() -> None:
    """Remove stored model outputs from Streamlit session state."""
    for key in list(st.session_state.keys()):
        if key.startswith("last_"):
            del st.session_state[key]


def available_cols(df: pd.DataFrame, cols: list[str]) -> list[str]:
    """Return only columns that exist and contain at least one non-empty value."""
    available = []

    for col in cols:
        if col not in df.columns:
            continue

        if df[col].notna().any():
            available.append(col)

    return available


def safe_float(value: Any) -> float | None:
    """Convert value to float if possible, otherwise return None."""
    if value is None or pd.isna(value):
        return None

    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def show_metric(label: str, value: Any, suffix: str = "", decimals: int = 2) -> None:
    """Show a Streamlit metric, safely handling None/non-numeric values."""
    numeric_value = safe_float(value)

    if numeric_value is None:
        st.metric(label, "—")
    else:
        st.metric(label, f"{numeric_value:.{decimals}f}{suffix}")


def make_run_label(run_number: int, crop_overrides: dict | None) -> str:
    """Create a readable label for the comparison plot."""
    if not crop_overrides:
        return f"Run {run_number}: default crop"

    label_parts = []

    for key in ["RUE", "Tsum", "Tbase", "N_uptake_a", "N_uptake_b"]:
        if key in crop_overrides:
            label_parts.append(f"{key}={float(crop_overrides[key]):g}")

        if len(label_parts) >= 2:
            break

    if not label_parts:
        return f"Run {run_number}: edited crop"

    return f"Run {run_number}: " + ", ".join(label_parts)


def normalise_date_string(value: Any) -> str:
    """Convert date-like values from Streamlit/pandas data editors to yyyy-mm-dd."""
    return pd.to_datetime(value).date().isoformat()


# -----------------------------------------------------------------------------
# Plot helpers
# -----------------------------------------------------------------------------
def plot_line(df: pd.DataFrame, y_cols: list[str], title: str, y_label: str) -> None:
    cols = available_cols(df, y_cols)

    if not cols:
        st.info(f"No available columns for: {title}")
        return

    fig = px.line(
        df,
        x="DAS",
        y=cols,
        labels={
            "DAS": "Days after sowing",
            "value": y_label,
            "variable": "Variable",
        },
        title=title,
    )
    fig.update_layout(
        margin=dict(l=10, r=10, t=55, b=10),
        legend_title_text="",
        hovermode="x unified",
    )
    st.plotly_chart(fig, use_container_width=True)


def plot_bar(df: pd.DataFrame, y_cols: list[str], title: str, y_label: str) -> None:
    cols = available_cols(df, y_cols)

    if not cols:
        st.info(f"No available columns for: {title}")
        return

    fig = px.bar(
        df,
        x="DAS",
        y=cols,
        labels={
            "DAS": "Days after sowing",
            "value": y_label,
            "variable": "Variable",
        },
        title=title,
    )
    fig.update_layout(
        margin=dict(l=10, r=10, t=55, b=10),
        legend_title_text="",
        hovermode="x unified",
    )
    st.plotly_chart(fig, use_container_width=True)


def plot_run_history_line(
    run_history: list[dict],
    y_col: str,
    title: str,
    y_label: str,
    max_runs: int = 2,
) -> None:
    """Plot the same output variable for the latest model runs."""
    if not run_history:
        return

    visible_runs = run_history[-max_runs:]

    fig = go.Figure()

    for run in visible_runs:
        df = run["season_df"]

        if y_col not in df.columns or "DAS" not in df.columns:
            continue

        fig.add_trace(
            go.Scatter(
                x=df["DAS"],
                y=df[y_col],
                mode="lines",
                name=run["label"],
            )
        )

    if not fig.data:
        st.info(f"No available data for: {title}")
        return

    fig.update_layout(
        title=title,
        xaxis_title="Days after sowing",
        yaxis_title=y_label,
        legend_title="Model run",
        margin=dict(l=10, r=10, t=55, b=10),
        hovermode="x unified",
    )

    st.plotly_chart(fig, use_container_width=True)


