@st.dialog("How to use ARVIOR Labs")
def show_tutorial_dialog() -> None:
    st.markdown(
        """
        ARVIOR Labs is built as a small learning environment for crop, soil,
        water and nitrogen modelling.

        **1. Choose a scenario**  
        Select a dataset and one of the available treatments in the left panel.
        The treatment loads the default trial management from the validation database.

        **2. Check or edit the input values**  
        Open the foldable sections in the middle panel. You can inspect and change
        the site properties, fertilizer events, irrigation events and optional crop parameters.

        **3. Run the model**  
        Click **Run ARVIOR** in the left panel. The app sends the selected scenario
        to the local ARVIOR API.

        **4. Read the outputs**  
        The right panel shows the model results. Use the tabs to inspect growth,
        nitrogen, water balance and stress factors.

        **5. Compare runs**  
        Change an input, run ARVIOR again, and the app compares the latest two runs
        in the relevant result tabs.

        **Tip:** use **Reset scenario defaults** when you want to return the selected
        scenario to its original database values.
        """
    )

    st.info(
        "Make sure the local ARVIOR API is running before clicking Run ARVIOR. "
        "Use Test API connection in the left panel to check this."
    )


# -----------------------------------------------------------------------------
# Result rendering
# -----------------------------------------------------------------------------
def render_model_results(
    season_df: pd.DataFrame,
    irrigation_events: list[dict],
    crop_id: str,
    treatment_key: str,
    run_history: list[dict] | None = None,
) -> None:
    """Render summary metrics, graphs and CSV download for the latest model run."""
    final_row = season_df.iloc[-1]

    st.markdown('<div class="results-section-title">Summary statistics</div>', unsafe_allow_html=True)

    metric_cols_1 = st.columns(5)

    with metric_cols_1[0]:
        if "Biomass_actual_cum" in season_df.columns:
            show_metric(
                "Final biomass",
                final_row["Biomass_actual_cum"],
                suffix=" t DM/ha",
                decimals=2,
            )

    with metric_cols_1[1]:
        if "Yield_dm" in season_df.columns:
            show_metric("Yield DM", final_row["Yield_dm"], decimals=2)

    with metric_cols_1[2]:
        if "Yield_fresh" in season_df.columns:
            show_metric("Fresh yield", final_row["Yield_fresh"], decimals=2)

    with metric_cols_1[3]:
        if "N_cum_actual" in season_df.columns:
            show_metric(
                "N uptake",
                final_row["N_cum_actual"],
                suffix=" kg N/ha",
                decimals=1,
            )

    with metric_cols_1[4]:
        total_irrigation = sum(float(e["mm"]) for e in irrigation_events)
        st.metric("Total irrigation", f"{total_irrigation:.0f} mm")

    metric_cols_2 = st.columns(5)

    with metric_cols_2[0]:
        if "NO3_leached" in season_df.columns:
            st.metric(
                "Total NO₃ leached",
                f"{float(season_df['NO3_leached'].sum()):.1f} kg N/ha",
            )

    with metric_cols_2[1]:
        if "N_denitrified" in season_df.columns:
            st.metric(
                "Denitrified N",
                f"{float(season_df['N_denitrified'].sum()):.1f} kg N/ha",
            )

    with metric_cols_2[2]:
        if "NH3_volatilized" in season_df.columns:
            st.metric(
                "NH₃ volatilized",
                f"{float(season_df['NH3_volatilized'].sum()):.1f} kg N/ha",
            )

    with metric_cols_2[3]:
        if "ks" in season_df.columns:
            water_stress_days = int((season_df["ks"] < 0.99).sum())
            st.metric("Water-stress days", f"{water_stress_days}")

    with metric_cols_2[4]:
        if "N_stress_factor" in season_df.columns:
            n_stress_days = int((season_df["N_stress_factor"] < 0.99).sum())
            st.metric("N-stress days", f"{n_stress_days}")

    st.markdown('<div class="results-section-title">Graphs</div>', unsafe_allow_html=True)

