def render_site_inputs(
    site_display: dict,
    scenario_config: dict,
    widget_key: str,
) -> tuple[dict, float, float]:
    """Render editable site inputs and return site overrides plus initial N settings."""
    current_soil_id = str(site_display.get("soil_id", "Loamy"))

    soil_options = ["Sand", "Loamy", "Clay"]
    if current_soil_id not in soil_options:
        soil_options.insert(0, current_soil_id)

    location_cols = st.columns(2)

    with location_cols[0]:
        st.markdown("#### Location")
        st.write(str(site_display.get("name", "")))

        soil_id = st.selectbox(
            "Soil type",
            soil_options,
            index=soil_options.index(current_soil_id),
            key=f"soil_id_{widget_key}",
        )

        sample_depth_cm = st.number_input(
            "Sample depth (cm)",
            value=float(site_display.get("sample_depth_cm")),
            min_value=1.0,
            max_value=100.0,
            step=1.0,
            key=f"sample_depth_{widget_key}",
        )

    with location_cols[1]:
        st.markdown("#### Soil chemistry")

        om_percent = st.number_input(
            "Organic matter (%)",
            value=float(site_display.get("OM_percent")),
            min_value=0.0,
            max_value=30.0,
            step=0.1,
            key=f"om_{widget_key}",
        )

        ph = st.number_input(
            "pH",
            value=float(site_display.get("pH")),
            min_value=3.0,
            max_value=10.0,
            step=0.1,
            key=f"ph_{widget_key}",
        )

        cn_ratio = st.number_input(
            "C/N ratio",
            value=float(site_display.get("CN_ratio")),
            min_value=1.0,
            max_value=50.0,
            step=0.5,
            key=f"cn_{widget_key}",
        )

    st.markdown("#### Nitrogen initialisation")

    n_cols = st.columns(2)
    with n_cols[0]:
        initial_n = st.number_input(
            "Initial mineral N at sowing (kg N/ha)",
            value=float(scenario_config["initial_mineral_n_kg_ha"]),
            min_value=0.0,
            step=5.0,
            key=f"initial_n_{widget_key}",
        )

    with n_cols[1]:
        initial_no3_fraction = st.number_input(
            "NO₃ fraction of initial mineral N",
            value=float(scenario_config["initial_no3_fraction"]),
            min_value=0.0,
            max_value=1.0,
            step=0.05,
            key=f"initial_no3_fraction_{widget_key}",
        )

    site_overrides = {
        "soil_id": soil_id,
        "OM_percent": float(om_percent),
        "CN_ratio": float(cn_ratio),
        "pH": float(ph),
        "sample_depth_cm": float(sample_depth_cm),
    }

    with st.expander("Site values sent to the API"):
        st.json(site_overrides)

    return site_overrides, float(initial_n), float(initial_no3_fraction)


def render_management_inputs(
    scenario_inputs: dict,
    widget_key: str,
) -> tuple[Any, Any, pd.DataFrame, pd.DataFrame]:
    """Render editable management inputs."""
    date_cols = st.columns(2)

    with date_cols[0]:
        sowing_date = st.date_input(
            "Sowing / start date",
            value=pd.to_datetime(scenario_inputs["sowing_date"]).date(),
            key=f"sowing_date_{widget_key}",
        )

    with date_cols[1]:
        harvest_date = st.date_input(
            "Harvest / end date",
            value=pd.to_datetime(scenario_inputs["harvest_date"]).date(),
            key=f"harvest_date_{widget_key}",
        )

    st.markdown("#### Fertilizer events")

    fertilizer_df = pd.DataFrame(scenario_inputs["fertilizer_events"])

    if fertilizer_df.empty:
        fertilizer_df = pd.DataFrame(columns=["date", "product_id", "kg_product_per_ha"])

    edited_fertilizer_df = st.data_editor(
        fertilizer_df,
        num_rows="dynamic",
        use_container_width=True,
        key=f"fertilizer_{widget_key}",
    )

    st.markdown("#### Irrigation events")

    irrigation_df = pd.DataFrame(scenario_inputs["irrigation_events"])

    if irrigation_df.empty:
        irrigation_df = pd.DataFrame(columns=["date", "mm"])

    edited_irrigation_df = st.data_editor(
        irrigation_df,
        num_rows="dynamic",
        use_container_width=True,
        key=f"irrigation_{widget_key}",
    )

    return sowing_date, harvest_date, edited_fertilizer_df, edited_irrigation_df


def render_advanced_crop_inputs(widget_key: str) -> dict | None:
    """Render optional crop parameter overrides."""
    st.caption(
        "Explore how crop parameters affect simulated growth, nitrogen uptake and stress. "
        "Changes are temporary and only apply to the current model run."
    )

    enable_advanced = st.checkbox(
        "Enable crop parameter editing",
        key=f"enable_advanced_{widget_key}",
    )

    if not enable_advanced:
        st.info("Crop parameter editing is disabled. The API uses the crop catalog defaults.")
        return None

    st.info(
        "These values are sent to the ARVIOR API as crop_overrides. "
        "They do not change the crop catalog permanently."
    )

    crop_cols = st.columns(2)

    with crop_cols[0]:
        tbase = st.number_input(
            "Tbase",
            value=4.0,
            help="Base temperature for thermal time accumulation. Below this temperature, crop development is limited.",
            key=f"tbase_{widget_key}",
        )

        tsum = st.number_input(
            "Tsum",
            value=1300.0,
            help="Thermal time requirement for crop development. Higher values generally delay maturity.",
            key=f"tsum_{widget_key}",
        )

        i50a = st.number_input(
            "I50a",
            value=300.0,
            help="Controls the first half of the crop growth curve. Lower values shift early growth forward.",
            key=f"i50a_{widget_key}",
        )

        i50b = st.number_input(
            "I50b",
            value=500.0,
            help="Controls the later part of the crop growth curve and canopy development.",
            key=f"i50b_{widget_key}",
        )

    with crop_cols[1]:
        rue = st.number_input(
            "RUE",
            value=1.6,
            help="Radiation use efficiency. Higher values increase potential biomass production per unit intercepted radiation.",
            key=f"rue_{widget_key}",
        )

        n_uptake_a = st.number_input(
            "N_uptake_a",
            value=61.0,
            help="Nitrogen dilution parameter controlling the crop nitrogen demand level.",
            key=f"n_uptake_a_{widget_key}",
        )

        n_uptake_b = st.number_input(
            "N_uptake_b",
            value=0.44,
            help="Nitrogen dilution parameter controlling how crop N concentration declines with biomass.",
            key=f"n_uptake_b_{widget_key}",
        )

        n_dilution_fmin = st.number_input(
            "N_dilution_fmin",
            value=0.35,
            help="Minimum nitrogen dilution fraction under strong nitrogen limitation.",
            key=f"n_dilution_fmin_{widget_key}",
        )

    crop_overrides = {
        "Tbase": float(tbase),
        "Tsum": float(tsum),
        "I50a": float(i50a),
        "I50b": float(i50b),
        "RUE": float(rue),
        "N_uptake_a": float(n_uptake_a),
        "N_uptake_b": float(n_uptake_b),
        "N_dilution_fmin": float(n_dilution_fmin),
    }

    with st.expander("Crop parameters sent to the API"):
        st.json(crop_overrides)

    return crop_overrides


# -----------------------------------------------------------------------------
# Running the model
# -----------------------------------------------------------------------------
def parse_fertilizer_events(edited_fertilizer_df: pd.DataFrame) -> list[dict]:
    events = []

    for e in edited_fertilizer_df.to_dict(orient="records"):
        if (
            pd.notna(e.get("date"))
            and pd.notna(e.get("product_id"))
            and pd.notna(e.get("kg_product_per_ha"))
        ):
            events.append(
                {
                    "date": normalise_date_string(e["date"]),
                    "product_id": str(e["product_id"]),
                    "kg_product_per_ha": float(e["kg_product_per_ha"]),
                }
            )

    return events


def parse_irrigation_events(edited_irrigation_df: pd.DataFrame) -> list[dict]:
    events = []

    for e in edited_irrigation_df.to_dict(orient="records"):
        if pd.notna(e.get("date")) and pd.notna(e.get("mm")):
            events.append(
                {
                    "date": normalise_date_string(e["date"]),
                    "mm": float(e["mm"]),
                }
            )

    return events


def run_selected_scenario(
    *,
    con,
    scenario_name: str,
    scenario_config: dict,
    treatment_key: str,
    sowing_date: Any,
    harvest_date: Any,
    edited_fertilizer_df: pd.DataFrame,
    edited_irrigation_df: pd.DataFrame,
    site_overrides: dict,
    crop_overrides: dict | None,
    initial_n: float,
    initial_no3_fraction: float,
) -> None:
    """Run ARVIOR for the selected scenario and store results in session state."""
    sowing_date_str = pd.to_datetime(sowing_date).date().isoformat()
    harvest_date_str = pd.to_datetime(harvest_date).date().isoformat()

    fertilizer_events = parse_fertilizer_events(edited_fertilizer_df)
    irrigation_events = parse_irrigation_events(edited_irrigation_df)

    run_mode = scenario_config.get("run_mode", "warmup_then_season")

    warmup_request = None
    warmup_response = None

    if run_mode == "warmup_then_season":
        warmup_start = (
            pd.to_datetime(sowing_date_str)
            - pd.Timedelta(days=int(scenario_config["warmup_days"]))
        ).date().isoformat()

        warmup_end = (
            pd.to_datetime(sowing_date_str) - pd.Timedelta(days=1)
        ).date().isoformat()

        warmup_request = build_run_request(
            con=con,
            site_id=scenario_config["site_id"],
            crop_id=scenario_config["crop_id"],
            sowing_date=sowing_date_str,
            harvest_date=harvest_date_str,
            window_start=warmup_start,
            window_end=warmup_end,
            fertilizer_events=fertilizer_events,
            irrigation_events=irrigation_events,
            prev_state=None,
            site_overrides=site_overrides,
            crop_overrides=crop_overrides,
        )

        warmup_response = run_arvior(warmup_request)
        warmup_state = warmup_response["next_state"]

    else:
        warmup_state = None

    season_prev_state, init_n_debug = inject_initial_mineral_n(
        prev_state=warmup_state,
        nmin_kg_ha=float(initial_n),
        no3_fraction=float(initial_no3_fraction),
    )

    season_request = build_run_request(
        con=con,
        site_id=scenario_config["site_id"],
        crop_id=scenario_config["crop_id"],
        sowing_date=sowing_date_str,
        harvest_date=harvest_date_str,
        window_start=sowing_date_str,
        window_end=harvest_date_str,
        fertilizer_events=fertilizer_events,
        irrigation_events=irrigation_events,
        prev_state=season_prev_state,
        site_overrides=site_overrides,
        crop_overrides=crop_overrides,
    )

    season_response = run_arvior(season_request)

    season_df = pd.DataFrame(season_response["df"])
    season_df = add_days_after_sowing(season_df, sowing_date=sowing_date_str)

    st.session_state["last_warmup_request"] = warmup_request
    st.session_state["last_warmup_response"] = warmup_response
    st.session_state["last_season_request"] = season_request
    st.session_state["last_season_response"] = season_response
    st.session_state["last_season_df"] = season_df
    st.session_state["last_init_n_debug"] = init_n_debug
    st.session_state["last_crop_overrides"] = crop_overrides

    st.session_state["last_run_counter"] = st.session_state.get("last_run_counter", 0) + 1

    run_label = make_run_label(
        run_number=st.session_state["last_run_counter"],
        crop_overrides=crop_overrides,
    )

    run_history = st.session_state.get("last_run_history", [])
    run_history.append(
        {
            "label": run_label,
            "scenario": scenario_name,
            "treatment": treatment_key,
            "crop_overrides": crop_overrides,
            "season_df": season_df.copy(),
        }
    )

    st.session_state["last_run_history"] = run_history[-2:]
    st.session_state["last_irrigation_events"] = irrigation_events
    st.session_state["last_crop_id"] = scenario_config["crop_id"]
    st.session_state["last_treatment_key"] = treatment_key
    st.session_state["last_run_label"] = f"{scenario_name} — {treatment_key}"


